291	export function markThreadVisited(
292	  state: AppState,
293	  threadId: ThreadId,
294	  visitedAt?: string,
295	): AppState {
296	  const at = visitedAt ?? new Date().toISOString();
297	  const visitedAtMs = Date.parse(at);
298	  const threads = updateThread(state.threads, threadId, (thread) => {
299	    const previousVisitedAtMs = thread.lastVisitedAt ? Date.parse(thread.lastVisitedAt) : NaN;
300	    if (
301	      Number.isFinite(previousVisitedAtMs) &&
302	      Number.isFinite(visitedAtMs) &&
303	      previousVisitedAtMs >= visitedAtMs
304	    ) {
305	      return thread;
306	    }
307	    return { ...thread, lastVisitedAt: at };
308	  });
309	  return threads === state.threads ? state : { ...state, threads };
310	}
311	
312	export function markThreadUnread(state: AppState, threadId: ThreadId): AppState {
313	  const threads = updateThread(state.threads, threadId, (thread) => {
314	    if (!thread.latestTurn?.completedAt) return thread;
315	    const latestTurnCompletedAtMs = Date.parse(thread.latestTurn.completedAt);
316	    if (Number.isNaN(latestTurnCompletedAtMs)) return thread;
317	    const unreadVisitedAt = new Date(latestTurnCompletedAtMs - 1).toISOString();
318	    if (thread.lastVisitedAt === unreadVisitedAt) return thread;
319	    return { ...thread, lastVisitedAt: unreadVisitedAt };
320	  });
321	  return threads === state.threads ? state : { ...state, threads };
322	}
323	
324	export function toggleProject(state: AppState, projectId: Project["id"]): AppState {
325	  return {
326	    ...state,
327	    projects: state.projects.map((p) => (p.id === projectId ? { ...p, expanded: !p.expanded } : p)),
328	  };
329	}
330	
331	export function setProjectExpanded(
332	  state: AppState,
333	  projectId: Project["id"],
334	  expanded: boolean,
335	): AppState {
336	  let changed = false;
337	  const projects = state.projects.map((p) => {
338	    if (p.id !== projectId || p.expanded === expanded) return p;
339	    changed = true;
340	    return { ...p, expanded };
341	  });
342	  return changed ? { ...state, projects } : state;
343	}
344	
345	export function setError(state: AppState, threadId: ThreadId, error: string | null): AppState {
346	  const threads = updateThread(state.threads, threadId, (t) => {
347	    if (t.error === error) return t;
348	    return { ...t, error };
349	  });
350	  return threads === state.threads ? state : { ...state, threads };
351	}
