function applyThemeColors(theme: ThemeDefinition, suppressTransitions: boolean): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle .dark class based on theme's isDark flag
  document.documentElement.classList.toggle("dark", theme.isDark);

  // Set all CSS custom properties from theme colors
  const style = document.documentElement.style;
  // Map camelCase keys to kebab-case CSS var names
  for (const [key, value] of Object.entries(theme.colors)) {
