import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useState,
  type ReactNode,
} from "react";
import {
  getTheme,
  listThemes,
  type Theme,
} from "@t3tools/shared/themes";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:custom-theme";
const DEFAULT_THEME_ID = "t3-dark";

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

interface ThemeContextValue {
  /** The currently active theme object. */
  theme: Theme;
  /** Switch to a different built-in theme by id. */
  setTheme: (id: string) => void;
  /** Every available built-in theme. */
  availableThemes: readonly Theme[];
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function getStoredThemeId(): string {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (typeof stored === "string" && getTheme(stored)) return stored;
  } catch {
    // localStorage may be unavailable (e.g. in some iframe sandboxes).
  }
  return DEFAULT_THEME_ID;
}

function resolveTheme(id: string): Theme {
  return getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
}

/**
 * Apply theme-specific CSS custom properties to the document root so that
 * downstream CSS and Tailwind utilities can reference them.
 */
function applyThemeProperties(theme: Theme): void {
  const root = document.documentElement;

  root.style.setProperty("--t3-theme-background", theme.colors.background);
  root.style.setProperty("--t3-theme-foreground", theme.colors.foreground);
  root.style.setProperty("--t3-theme-accent", theme.colors.accent);
  root.style.setProperty("--t3-theme-sidebar", theme.colors.sidebar);
  root.style.setProperty("--t3-theme-editor", theme.colors.editor);
  root.style.setProperty("--t3-theme-terminal", theme.colors.terminal);
  root.style.setProperty("--t3-theme-status-bar", theme.colors.statusBar);
  root.style.setProperty("--t3-theme-font-family", theme.fontFamily);
  root.style.setProperty("--t3-theme-font-size", `${String(theme.fontSize)}px`);

  // Toggle dark mode class — t3-light is the only light theme.
  const isDark = theme.id !== "t3-light";
  root.classList.toggle("dark", isDark);
}

// Apply eagerly on module load to prevent a flash of unstyled content.
applyThemeProperties(resolveTheme(getStoredThemeId()));

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [themeId, setThemeId] = useState(getStoredThemeId);

  const theme = resolveTheme(themeId);

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    if (!next) return;
    localStorage.setItem(STORAGE_KEY, id);
    setThemeId(id);
  }, []);

  useEffect(() => {
    applyThemeProperties(theme);
  }, [theme]);

  // Listen for cross-tab storage changes so that all windows stay in sync.
  useEffect(() => {
    const handleStorage = (e: StorageEvent) => {
      if (e.key === STORAGE_KEY) {
        const nextId = e.newValue ?? DEFAULT_THEME_ID;
        const next = getTheme(nextId);
        if (next) {
          setThemeId(nextId);
        }
      }
    };
    window.addEventListener("storage", handleStorage);
    return () => window.removeEventListener("storage", handleStorage);
  }, []);

  return (
    <ThemeContext value={{ theme, setTheme, availableThemes: listThemes() }}>
      {children}
    </ThemeContext>
  );
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Access the custom-theme system.
 *
 * Must be rendered inside a `<ThemeProvider>`.
 */
export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used within a <ThemeProvider>");
  }
  return ctx;
}

