import type { Theme } from "@t3tools/shared/themes";

import { useTheme } from "../themeContext";

/** A small grid of colour dots that previews a theme's palette. */
function ThemeSwatch({ theme }: { theme: Theme }) {
  const colors = [
    theme.colors.background,
    theme.colors.foreground,
    theme.colors.accent,
    theme.colors.sidebar,
  ];

  return (
    <span className="inline-flex gap-1" aria-hidden>
      {colors.map((color, i) => (
        <span
          key={i}
          className="size-3 rounded-full border border-border/40"
          style={{ backgroundColor: color }}
        />
      ))}
    </span>
  );
}

/**
 * Renders a list of available themes with colour-swatch previews.
 *
 * Drop this into any settings / sidebar surface; it reads its state from
 * `<ThemeProvider>` via the `useTheme()` hook.
 */
export function ThemeSelector() {
  const { theme: current, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme">
      {availableThemes.map((t) => {
        const selected = t.id === current.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center justify-between gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id)}
          >
            <span className="flex flex-col gap-0.5">
              <span className="text-sm font-medium">{t.name}</span>
              <ThemeSwatch theme={t} />
            </span>

            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

