/** Color slots for a T3 Code theme. */
export interface ThemeColors {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

/** A complete theme definition for T3 Code. */
export interface Theme {
  id: string;
  name: string;
  colors: ThemeColors;
  fontFamily: string;
  fontSize: number;
}

const builtInThemes: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0a0a0b",
      foreground: "#e5e5e5",
      accent: "#6366f1",
      sidebar: "#111113",
      editor: "#0a0a0b",
      terminal: "#0a0a0b",
      statusBar: "#111113",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#1a1a1a",
      accent: "#4f46e5",
      sidebar: "#f5f5f5",
      editor: "#ffffff",
      terminal: "#fafafa",
      statusBar: "#f0f0f0",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#0b0e14",
      foreground: "#bfbdb6",
      accent: "#e6b450",
      sidebar: "#0d1017",
      editor: "#0b0e14",
      terminal: "#0d1017",
      statusBar: "#0d1017",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
] as const;

const themeMap = new Map<string, Theme>(
  builtInThemes.map((t) => [t.id, t]),
);

/**
 * Look up a built-in theme by its `id`.
 * Returns `undefined` when the id is not recognised.
 */
export function getTheme(id: string): Theme | undefined {
  return themeMap.get(id);
}

/** Return every built-in theme. */
export function listThemes(): readonly Theme[] {
  return builtInThemes;
}

